getCurrentCartNotice.query:
query getCurrentCartNotice {
  getCurrentCartNotice: getCartNoticeGW {
    id
    message
    startDateTime
    endDateTime
    linkUrl
    __typename
  }
}

getGeneralCartUserInfo.query:
query getGeneralCartUserInfo($errorCode: Int) {
  getGeneralCartUserInfo: getGeneralCartUserInfoShopperGW(errorCode: $errorCode) {
    memberId
    membershipDetail {
      membership
      membershipNudgeType
      couponDiscount
      customTitle
      membershipDeliveryBenefitType
      __typename
    }
    __typename
  }
}

getShippingAddresses.query:
query getShippingAddresses {
  shippingAddress: getShippingAddressesV2ShopperGW {
    content {
      data {
        hash
        addressName
        zipCode
        baseAddress
        detailAddress
        roadNameYn
        latitude
        longitude
        primaryYn
        recentlyUsedYn
        buildingManagementNo
        __typename
      }
      __typename
    }
    __typename
  }
}

productsCount.query:
query productsCount {
  cartProductsCount: productsCountShopperGW {
    generalCart
    designatedCart
    __typename
  }
}

validOrderDeliveryAddress.query:
mutation validOrderDeliveryAddress($orderDeliveryAddressRequestInput: OrderDeliveryAddressRequestInput!) {
  validOrderDeliveryAddress: validOrderDeliveryAddress(
    orderDeliveryAddressRequestInput: $orderDeliveryAddressRequestInput
  ) {
    requestZipCode
    validAddress
    failMessage
    failType
    __typename
  }
}

calculateBenefitSummary.query:
mutation calculateBenefitSummary($benefitSummaryCalculateRequestInput: BenefitSummaryCalculateRequestInput!) {
  calculateBenefitSummary: calculateBenefitSummaryShopperGW(
    benefitSummaryCalculateRequestInput: $benefitSummaryCalculateRequestInput
  ) {
    totalPriceList {
      naverSellerNo
      totalPrice {
        cardPromotionPolicy {
          fullText
          policyUniqueId
          __typename
        }
        cardPromotionDiscountAmount
        myDiscountAmount
        totalProductPrice
        totalDeliveryFee
        totalDiscountAmount
        totalCouponDiscountAmount
        totalImmediateDiscountAmount
        totalOrderPrice
        discountedTotalDeliveryFee
        discountedTotalOrderPrice
        __typename
      }
      __typename
    }
    __typename
  }
}

getStoreCouponExist.query:
query getStoreCouponExist($accountNo: BigInt!, $merchantNo: BigInt!) {
  getStoreCouponExist: getStoreCouponExistShopperGW(
    accountNo: $accountNo
    merchantNo: $merchantNo
  ) {
    displayTooltip
    issuableCouponExist
    issuedCouponExist
    purchaseHistoryMap
    tooltipType
    __typename
  }
}
